var currentIndex int

func lb(w http.ResponseWriter, r *http.Request) {
    if len(serverPool.backends) == 0 {
        http.Error(w, "Service not available", http.StatusServiceUnavailable)
        return
    }
    peer := serverPool.backends[currentIndex]
    currentIndex = (currentIndex + 1) % len(serverPool.backends)
    peer.ReverseProxy.ServeHTTP(w, r)
}
```

Note: this has a data race if multiple goroutines call `lb` simultaneously. The next section fixes this with `atomic.AddUint64`.
